mapper.select:

where d.del_flag = '0'
  and d.buyer_id = #{subjectId}

    and d.dept_name like concat('%', #{deptName}, '%')


    and d.status = #{status}

order by d.parent_id, d.order_num, d.buyer_dept_id


where d.del_flag = '0'
  and d.buyer_id = #{buyerId}
  and d.buyer_dept_id = #{deptId}


where d.del_flag = '0'
  and d.buyer_id = #{buyerId}
  and d.dept_name = #{deptName}
  and d.parent_id = #{parentId}
limit 1

select count(1)
from buyer_dept
where del_flag = '0'
  and buyer_id = #{buyerId}
  and parent_id = #{deptId}

